  actionType TEXT NOT NULL DEFAULT 'action',                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
  createdAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
  UNIQUE(sessionId, night, actorUserId),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
  FOREIGN KEY (sessionId) REFERENCES WerewolfSession(id)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
);                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
CREATE TABLE "WerewolfRoom" ("id" INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT, "code" TEXT NOT NULL UNIQUE, "gmId" INTEGER NOT NULL, "isOpen" BOOLEAN NOT NULL DEFAULT true, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY ("gmId") REFERENCES "User"("id"));                                                                                                                                                                                                                                                                                                                                                                
CREATE TABLE "WerewolfRoomPlayer" ("id" INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT, "roomId" INTEGER NOT NULL, "userId" INTEGER NOT NULL, "seatName" TEXT NOT NULL, "joinedAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, seatOrder INTEGER DEFAULT 0, FOREIGN KEY ("roomId") REFERENCES "WerewolfRoom"("id"), FOREIGN KEY ("userId") REFERENCES "User"("id"), UNIQUE("roomId", "userId"));                                                                                                                                                                                                                                                      
CREATE TABLE "WerewolfSession" ("id" INTEGER PRIMARY KEY AUTOINCREMENT, "roomId" INTEGER NOT NULL UNIQUE, "phase" TEXT NOT NULL DEFAULT 'SETUP', "selectedRoles" TEXT NOT NULL, "decoyRoles" TEXT NOT NULL DEFAULT '[]', "currentStep" TEXT, "winTeam" TEXT, "gameId" INTEGER UNIQUE, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, nightNumber INTEGER NOT NULL DEFAULT 0, dayNumber INTEGER NOT NULL DEFAULT 0, playerCount INTEGER NOT NULL DEFAULT 0, FOREIGN KEY ("roomId") REFERENCES "WerewolfRoom"("id"), FOREIGN KEY ("gameId") REFERENCES "WerewolfGame"("id"));     
CREATE TABLE "WerewolfSessionPlayer" ("id" INTEGER PRIMARY KEY AUTOINCREMENT, "sessionId" INTEGER NOT NULL, "userId" INTEGER NOT NULL, "role" TEXT NOT NULL, "team" TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'alive', UNIQUE("sessionId", "userId"), FOREIGN KEY ("sessionId") REFERENCES "WerewolfSession"("id"), FOREIGN KEY ("userId") REFERENCES "User"("id"));                                                                                                                                                                                                                                                                             
CREATE TABLE WerewolfVote (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
  id INTEGER PRIMARY KEY AUTOINCREMENT,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
  sessionId INTEGER NOT NULL,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
  day INTEGER NOT NULL DEFAULT 1,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
  voterUserId INTEGER NOT NULL,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
  targetUserId INTEGER NOT NULL,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
  createdAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
  UNIQUE(sessionId, day, voterUserId),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
  FOREIGN KEY (sessionId) REFERENCES WerewolfSession(id)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
);                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
CREATE TABLE "_prisma_migrations" (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
