CREATE TABLE "stock_out_log" ("id" INTEGER PRIMARY KEY AUTOINCREMENT, "stock_item_id" INTEGER NOT NULL, "qty" REAL NOT NULL, "reason" TEXT NOT NULL, "order_id" INTEGER, "created_by" INTEGER NOT NULL, "created_at" DATETIME DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY ("stock_item_id") REFERENCES "stock_items"("id"));                                                                                                                                                                                                                                                                                                                            
